+import type { AnyColumn } from '~/column.ts';
+import { is } from '~/entity.ts';
+import { Column } from '~/column.ts';
+import { SQL, sql, type SQLWrapper } from '../sql.ts';
+
+type WindowOrder = SQLWrapper;
+export interface WindowFrameBoundary { readonly kind: 'unbounded preceding' | 'current row' | 'unbounded following' | 'preceding' | 'following'; readonly value?: number }
+export interface WindowFrame { readonly mode: 'rows' | 'range'; readonly from: WindowFrameBoundary; readonly to: WindowFrameBoundary }
+export interface WindowSpec { partitionBy?: WindowOrder | WindowOrder[]; orderBy?: WindowOrder | WindowOrder[]; frame?: WindowFrame }
+
+export const unboundedPreceding: WindowFrameBoundary = { kind: 'unbounded preceding' };
+export const currentRow: WindowFrameBoundary = { kind: 'current row' };
+export const unboundedFollowing: WindowFrameBoundary = { kind: 'unbounded following' };
+
+function offsetBoundary(name: 'preceding' | 'following', value: number): WindowFrameBoundary {
+	if (!Number.isInteger(value) || value < 0) throw new Error(`${name}() requires a non-negative integer, received ${value}`);
+	return { kind: name, value };
+}
+export const preceding = (value: number): WindowFrameBoundary => offsetBoundary('preceding', value);
+export const following = (value: number): WindowFrameBoundary => offsetBoundary('following', value);
+
+function boundaryPosition(boundary: WindowFrameBoundary): number {
+	switch (boundary.kind) {
+		case 'unbounded preceding': return -Infinity;
+		case 'preceding': return -boundary.value!;
+		case 'current row': return 0;
+		case 'following': return boundary.value!;
+		case 'unbounded following': return Infinity;
+	}
+}
+function frame(mode: WindowFrame['mode'], spec: { from: WindowFrameBoundary; to: WindowFrameBoundary }): WindowFrame {
+	if (boundaryPosition(spec.from) > boundaryPosition(spec.to)) throw new Error('Window frame "from" boundary must not be ordered after "to"');
+	return { mode, ...spec };
+}
+export const rows = (spec: { from: WindowFrameBoundary; to: WindowFrameBoundary }): WindowFrame => frame('rows', spec);
+export const range = (spec: { from: WindowFrameBoundary; to: WindowFrameBoundary }): WindowFrame => frame('range', spec);
+
+function frameBoundarySql(boundary: WindowFrameBoundary): SQL {
+	return boundary.value === undefined ? sql.raw(boundary.kind) : sql.raw(`${boundary.value} ${boundary.kind}`);
+}
+function specSql(spec: WindowSpec): SQL {
+	const parts: SQL[] = [];
+	const partitionBy = spec.partitionBy && (Array.isArray(spec.partitionBy) ? spec.partitionBy : [spec.partitionBy]);
+	const orderBy = spec.orderBy && (Array.isArray(spec.orderBy) ? spec.orderBy : [spec.orderBy]);
+	if (partitionBy?.length) parts.push(sql`partition by ${sql.join(partitionBy, sql`, `)}`);
+	if (orderBy?.length) parts.push(sql`order by ${sql.join(orderBy, sql`, `)}`);
+	if (spec.frame) parts.push(sql`${sql.raw(spec.frame.mode)} between ${frameBoundarySql(spec.frame.from)} and ${frameBoundarySql(spec.frame.to)}`);
+	return sql.join(parts, sql` `);
+}
+
+export class WindowFunction<T> implements SQLWrapper {
+	constructor(private readonly expression: SQL<T>) {}
+	over(spec: WindowSpec | string): SQL<T> {
+		return typeof spec === 'string'
+			? sql`${this.expression} over ${sql.identifier(spec)}`
+			: sql`${this.expression} over (${specSql(spec)})`;
+	}
+	getSQL(): SQL<T> { return this.expression; }
+}
+
+function positional(name: string, values: (SQLWrapper | number | undefined)[]): WindowFunction<unknown> {
+	const args = values.filter((value): value is SQLWrapper | number => value !== undefined).map((value) =>
+		typeof value === 'number' ? sql.raw(String(value)) : value);
+	return new WindowFunction(sql`${sql.raw(name)}(${sql.join(args, sql`, `)})`);
+}
+function positiveInteger(name: string, value: number): void {
+	if (!Number.isInteger(value) || value <= 0) throw new Error(`${name}() requires a positive integer, received ${value}`);
+}
+type Value<T extends SQLWrapper> = T extends AnyColumn ? T['_']['data'] : T extends SQL<infer U> ? U : unknown;
+
+export const rowNumber = (): WindowFunction<number> => positional('row_number', []) as WindowFunction<number>;
+export const rank = (): WindowFunction<number> => positional('rank', []) as WindowFunction<number>;
+export const denseRank = (): WindowFunction<number> => positional('dense_rank', []) as WindowFunction<number>;
+export const ntile = (buckets: number): WindowFunction<number> => { positiveInteger('ntile', buckets); return positional('ntile', [buckets]) as WindowFunction<number>; };
+export const percentRank = (): WindowFunction<number> => positional('percent_rank', []) as WindowFunction<number>;
+export const cumeDist = (): WindowFunction<number> => positional('cume_dist', []) as WindowFunction<number>;
+export function lag<T extends SQLWrapper>(value: T): WindowFunction<Value<T> | null>;
+export function lag<T extends SQLWrapper>(value: T, offset: number, defaultValue: SQLWrapper): WindowFunction<Value<T>>;
+export function lag<T extends SQLWrapper>(value: T, offset?: number, defaultValue?: SQLWrapper): WindowFunction<Value<T> | null> { return positional('lag', [value, offset, defaultValue]) as WindowFunction<Value<T> | null>; }
+export function lead<T extends SQLWrapper>(value: T): WindowFunction<Value<T> | null>;
+export function lead<T extends SQLWrapper>(value: T, offset: number, defaultValue: SQLWrapper): WindowFunction<Value<T>>;
+export function lead<T extends SQLWrapper>(value: T, offset?: number, defaultValue?: SQLWrapper): WindowFunction<Value<T> | null> { return positional('lead', [value, offset, defaultValue]) as WindowFunction<Value<T> | null>; }
+export const firstValue = <T extends SQLWrapper>(value: T): WindowFunction<Value<T> | null> => positional('first_value', [value]) as WindowFunction<Value<T> | null>;
+export const lastValue = <T extends SQLWrapper>(value: T): WindowFunction<Value<T> | null> => positional('last_value', [value]) as WindowFunction<Value<T> | null>;
+export const nthValue = <T extends SQLWrapper>(value: T, nth: number): WindowFunction<Value<T> | null> => { positiveInteger('nthValue', nth); return positional('nth_value', [value, nth]) as WindowFunction<Value<T> | null>; };
+export const windowSum = <T extends SQLWrapper>(value: T): WindowFunction<string | null> => positional('sum', [value]) as WindowFunction<string | null>;
+export const windowAvg = <T extends SQLWrapper>(value: T): WindowFunction<string | null> => positional('avg', [value]) as WindowFunction<string | null>;
+export const windowMin = <T extends SQLWrapper>(value: T): WindowFunction<Value<T> | null> => new WindowFunction(sql`min(${value})`.mapWith(is(value, Column) ? value : String) as SQL<Value<T> | null>);
+export const windowMax = <T extends SQLWrapper>(value: T): WindowFunction<Value<T> | null> => new WindowFunction(sql`max(${value})`.mapWith(is(value, Column) ? value : String) as SQL<Value<T> | null>);
+export const windowCount = (value?: SQLWrapper): WindowFunction<number> => new WindowFunction(sql`count(${value ?? sql.raw('*')})`.mapWith(Number));
