+	expect(new PgDialect().sqlToQuery(query.getSQL())).toEqual({
+		sql: 'select row_number() over (order by "users"."name" rows between unbounded preceding and current row), ntile(2) over (), lag("users"."name", 0) over (), count(*) over () from "users"',
+		params: [],
+	});
+});
+
+test('named windows are quoted and render before order by', () => {
+	const query = new PgQueryBuilder().select({ rank: rowNumber().over('rank window') }).from(users)
